function updateVawVacRow(city, brgy, ...args) { return updateFTJSRowGeneric('VAW-VAC Incidents', city, brgy, args); }
function updateBarcoBrgyRow(city, brgy, ...args) { return updateFTJSRowGeneric('BARCO', city, brgy, args); }
