      // Keep track of the first row for this barangay that is empty or says "Not Submitted"
      // Used for Pass 2 if no specific week match is found
      if (firstEmptyBrgyRow === -1 && (rowWeekRaw === "" || rowWeekRaw.toUpperCase() === "NOT SUBMITTED" || rowWeekRaw === "undefined")) {
        firstEmptyBrgyRow = i + 1;
      }
    }
  }

  // PASS 2: If no exact week match, use the first empty/placeholder row found for this barangay
  if (firstEmptyBrgyRow !== -1) {
    sheet.getRange(firstEmptyBrgyRow, 3, 1, processedData.length).setValues([processedData]);
    if (timestampCol !== -1) {
        sheet.getRange(firstEmptyBrgyRow, timestampCol).setValue(webTimestamp);
    }
    SpreadsheetApp.flush();
    return "Success (Populated Placeholder Row)";
  }

  // PASS 3: If no row at all, append new
  const newRow = [city, brgy, ...processedData];
  if (timestampCol !== -1) {
    while (newRow.length < timestampCol - 1) newRow.push("");
    newRow[timestampCol - 1] = webTimestamp;
  }
  sheet.appendRow(newRow);
  SpreadsheetApp.flush();
  return "Success (New Week Created)";
}

